  const headInjection = `
    <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
    <style>
      html, body { margin: 0; padding: 0; background: #0c0c0c; overflow-x: hidden; width: 100vw; }
      body { -webkit-overflow-scrolling: touch; }
      #miron-scaler { transform-origin: top left; transition: opacity 0.3s ease; opacity: 0; width: 909px; }
      * { -webkit-tap-highlight-color: transparent; user-select: text !important; -webkit-user-select: text !important; }
      ::selection { background: rgba(66, 215, 184, 0.3); }
    </style>
  `;
  html = html.replace('<head>', `<head>${headInjection}`);

  // 2. Wrap Body in Scaler and Inject the Handshake Script
  const bodyStartIdx = html.indexOf('<body>') + 6;
  const bodyEndIdx = html.lastIndexOf('</body>');
  const originalBody = html.slice(bodyStartIdx, bodyEndIdx);

  const bodyWrap = `
    <div id="miron-scaler">${originalBody}</div>
    <script>
      (function() {
        const scaler = document.getElementById('miron-scaler');
        function applyScale() {
          const bookWidth = 909;
          const scale = window.innerWidth / bookWidth;
          scaler.style.transform = \`scale(\${scale})\`;
          scaler.style.opacity = "1";
          // Correction for Document height after scale
          document.body.style.height = (scaler.scrollHeight * scale) + 'px';
        }
        window.addEventListener('load', applyScale);
        window.addEventListener('resize', applyScale);

        // Selection Bridge
        document.addEventListener('selectionchange', () => {
          const sel = window.getSelection();
          if (sel.rangeCount > 0 && sel.toString().length > 0) {
            const rect = sel.getRangeAt(0).getBoundingClientRect();
