                text: sel.toString(), 
                rect: { top: rect.top, left: rect.left, width: rect.width, height: rect.height }
            }, '*');
          } else {
            window.parent.postMessage({ type: 'SELECTION_CLEAR' }, '*');
          }
        });
      })();
    <\/script>
  `;

  html = html.slice(0, bodyStartIdx) + bodyWrap + html.slice(bodyEndIdx);

