const BookReader = ({ book, onClose }) => {
    const [loading, setLoading] = useState(true);
    const [iframeSrc, setIframeSrc] = useState(null);
    const [isUiVisible, setIsUiVisible] = useState(true);
    const [activeExam, setActiveExam] = useState(null);
    const [contextMenu, setContextMenu] = useState(null);
    const [mironInsight, setMironInsight] = useState(null);

    const iframeRef = useRef(null);

    useEffect(() => {
        const fetchBook = async () => {
            try {
                setLoading(true);
                const response = await fetch('https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/book-reader', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ action: 'get_book_compressed', book_path: book.path })
                });
                const blob = await response.blob();
                setIframeSrc(URL.createObjectURL(blob));
            } catch (err) {
                console.error("Error loading book:", err);
                onClose();
            } finally {
                setLoading(false);
            }
        };
        if (book?.path) fetchBook();
        return () => iframeSrc && URL.revokeObjectURL(iframeSrc);
    }, [book]);

    useEffect(() => {
        const handleMessages = (e) => {
            const data = e.data;
            if (data.type === 'OPEN_EXAM') {
                setActiveExam({
                    id: data.examId,
                    targetQuestionId: data.questionId,
                    course_name: data.courseName || "Archive",
                    course_code: data.courseCode || "EXAM",
                    time_allowed_minutes: 60
                });
            }
            if (data.type === 'SELECTION_DATA') {
                setContextMenu({
                    x: data.rect.left + (data.rect.width / 2),
                    y: data.rect.top,
                    text: data.text
                });
            }
            if (data.type === 'SELECTION_CLEAR') {
                setContextMenu(null);
            }
        };
        window.addEventListener('message', handleMessages);
        return () => window.removeEventListener('message', handleMessages);
    }, []);

    return (
        <div className="reader-root">
            <div id="viewport" style={{ cursor: 'default' }}>
                {iframeSrc && (
                    <iframe 
                        ref={iframeRef}
                        id="book-iframe" 
                        src={iframeSrc}
                        style={{ width: '100%', height: '100%', border: 'none', pointerEvents: 'auto' }}
                        title="Book Content"
                    />
                )}
                {loading && <div className="loading-spinner">Synchronizing Neural Path...</div>}
            </div>

            {/* UI LAYER OVERLAYS */}
            <div id="ui-layer" className={isUiVisible ? '' : 'hidden'}>
                <div className="ui-bar reader-header">
                    <div className="header-left">
                        <div className="icon-btn" onClick={onClose}>
                            <svg className="reader-svg" viewBox="0 0 24 24"><path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/></svg>
                        </div>
                        <div className="header-title">{book?.title}</div>
                    </div>
                </div>
            </div>

            {contextMenu && (
                <div className="reader-ctx-menu" style={{ left: contextMenu.x - 130, top: contextMenu.y - 120 }}>
                    <div className="ctx-primary" onClick={() => { setMironInsight({ text: contextMenu.text, conversation: [] }); setContextMenu(null); }}>
                        <i className="fa-solid fa-wand-magic-sparkles"></i>
                        <span>Ask Miron</span>
                    </div>
                </div>
            )}

            {activeExam && <ExamSession exam={activeExam} onClose={() => setActiveExam(null)} />}
        </div>
    );
};

export default BookReader;

