            insertIdx += boundaryPattern.length;
            const injection = `\n<div class="miron-portal-container"><div class="miron-challenge-anchor" data-questions='${JSON.stringify(qList).replace(/'/g, "&apos;")}'></div></div>\n`;
            html = html.slice(0, insertIdx) + injection + html.slice(insertIdx);
          }
        }
      }
    }
  }

