    <style>
      html, body { margin: 0; padding: 0; background: #0c0c0c; overflow-x: hidden; width: 100vw; }
      #miron-scroll-wrapper { position: relative; width: 100vw; overflow-x: hidden; }
      #miron-scaler { transform-origin: 0 0; width: 909px; position: absolute; top: 0; left: 0; opacity: 0; transition: opacity 0.4s; }
      * { -webkit-tap-highlight-color: transparent; }
      .miron-portal-container { position: relative; z-index: 999; display: block; margin: 40px 0; background: #0c0c0c; width: 909px; }
    </style>
  `;
  html = html.replace('<head>', `<head>${headInjection}`);

  const bodyStartIdx = html.indexOf('<body>') + 6;
  const bodyEndIdx = html.lastIndexOf('</body>');
  const originalBody = html.slice(bodyStartIdx, bodyEndIdx);

  const bodyWrap = `
    <div id="miron-scroll-wrapper">
      <div id="miron-scaler">${originalBody}</div>
    </div>
    <script>
      (function() {
        const scaler = document.getElementById('miron-scaler');
        const wrapper = document.getElementById('miron-scroll-wrapper');
        function apply() {
          const scale = window.innerWidth / 909;
          scaler.style.transform = \`scale(\${scale})\`;
          wrapper.style.height = (scaler.offsetHeight * scale) + 'px';
          scaler.style.opacity = "1";
        }
        window.onload = apply;
        window.onresize = apply;
        document.addEventListener('selectionchange', () => {
          const sel = window.getSelection();
          if (sel.rangeCount > 0 && sel.toString().trim().length > 0) {
            const rect = sel.getRangeAt(0).getBoundingClientRect();
            window.parent.postMessage({ type: 'SELECTION_DATA', text: sel.toString(), rect }, '*');
          } else { window.parent.postMessage({ type: 'SELECTION_CLEAR' }, '*'); }
        });
      })();
    <\/script>
  `;
  html = html.slice(0, bodyStartIdx) + bodyWrap + html.slice(bodyEndIdx);

